damage.damageScript:
// Apply damage
// First deduct from Temp HP
let damage = value;
// Ignore negative damage as that is what healing is for
if (damage > 0) {
  const oldTempHp = parseInt(record.data?.tempHp || "0", 10);
  const newTempHp = Math.max(oldTempHp - damage, 0);
  damage = Math.max(damage - oldTempHp, 0);

  if (newTempHp !== oldTempHp) {
    api.setValue("data.tempHp", newTempHp);
  }

  var curhp = parseInt(record.data?.curhp, "0", 10);
  curhp -= damage;
  if (curhp < 0) {
    curhp = 0;
  }
  if (curhp > record.data?.hitpoints) {
    curhp = record.data?.hitpoints;
  }
  api.setValue("data.curhp", curhp);
}

// If damage > 0, float text
const token = api.getToken();
if (value > 0 && token) {
  if (curhp <= 0) {
    if (token.recordType === "npcs") {
      api.addEffect("Dead", token);
    } else {
      api.addEffects(["Unconscious", "Prone"], token);
    }
  }
  api.floatText(token, `-${value}`, "#FF0000");
}

damage.healingScript:
// Apply damage
// Ignore negative healing as that is what damage is for
// This script ignores tempHp, as it is not a factor in healing
if (value > 0) {
  var curhp = record.data?.curhp || 0;
  curhp += value;
  if (curhp < 0) {
    curhp = 0;
  }
  if (curhp > record.data?.hitpoints) {
    curhp = record.data?.hitpoints;
  }
  api.setValue("data.curhp", curhp);
}

// If healing > 0, float text
const token = api.getToken();
if (value > 0 && token) {
  api.floatText(token, `+${value}`, "#1bc91b");
}

combatTracker.onTokenAdd:
const rollHp = api.getSetting('rollHp') === 'yes';

const hitDice = data?.token?.data?.hitDice;

// If this is an NPC with hitdice and rollHp is enabled, roll for the HP
if (rollHp && hitDice && data?.token?.recordType === 'npcs') {
  const hitPointsRoll = api.rollInstant(hitDice);
  const hitPoints = hitPointsRoll?.total;
  api.setValueOnToken(data?.token, 'data.curhp', hitPoints);
  api.setValueOnToken(data?.token, 'data.hitpoints', hitPoints);
}

combatTracker.onEncounterEnd:
// On Encounter End, we want tally the XP for all tokens that were enemies
const enemies = (data?.tokens || []).filter((t) => t?.faction === "enemy");
const xp = enemies.reduce((acc, token) => {
  const xpString = token?.data?.xp || "0";
  let xpValue;

  if (token?.data?.inLair === true && xpString.includes("in lair")) {
    // Extract the "in lair" XP value if token is in lair
    const match = xpString.match(/or\s*([\d,]+)\s*in lair/);
    xpValue = match ? match[1].replace(/,/g, "") : xpString.replace(/,/g, "");
  } else {
    // Use the first number if not in lair or no "in lair" value exists
    xpValue = xpString.split(",or")[0].replace(/,/g, "");
  }

  return acc + parseInt(xpValue, 10);
}, 0);

// Here is a macro to award the XP to the player
let macro = "";
if (enemies.length > 0) {
  macro = `\`\`\`Award_XP
if (isGM) {
  api.awardExp(${xp}, 'Encounter with ${enemies.length} enemies.');
  api.editMessage(null, 'Awarded ${xp} XP to the Party.');
}
\`\`\`
`;

  api.sendMessage(
    `[center]Encounter Ended - Total XP: ${xp}[/center]\n${macro}`
  );
}

combatTracker.onTurnStart:
// On the Start of an NPCs Turn, check for any Recharge effects and if the value is within the range, send a message and remove the effect
const token = data?.token;
const effects = token?.effects || [];
const effectValues = token?.effectValues || {};
const rechargeEffect = effects.find(
  (effect) => effect?.name?.toLowerCase() === "recharge"
);

if (rechargeEffect) {
  const effectValue = effectValues?.[rechargeEffect?._id];
  const actionName = (effectValue || "").split("[")[0].trim();
  let effectDc = "6";
  if (effectValue && effectValue.includes("[")) {
    effectDc = parseInt(effectValue.split("[")[1].trim(), 10);
    if (isNaN(effectDc)) {
      effectDc = "6";
    }
  }

  api.roll(
    "1d6",
    {
      tokenId: token?._id,
      actionName: actionName,
      effectId: rechargeEffect?._id,
      dc: effectDc,
    },
    "recharge"
  );
}

// Update reactions if needed
if (token?.data?.usedReactions) {
  if (token?.data?.usedReactions > 0) {
    api.setValueOnToken(token, "data.usedReactions", 0);
  }
}

// Update legendary actions if needed
if (token?.data?.usedLegendaryActions) {
  if (token?.data?.usedLegendaryActions > 0) {
    api.setValueOnToken(token, "data.usedLegendaryActions", 0);
  }
}

// Check for Regeneration effects
const modifiers = getEffectsAndModifiersForToken(token, ["regeneration"], "");

// This gets applied to the token's HP via a macro
let healing = 0;
let effectsNames = "";
modifiers.forEach((modifier) => {
  if (typeof modifier.value === "number" && modifier.value > 0) {
    healing += modifier.value;
    if (effectsNames !== "") {
      effectsNames += ", ";
    }
    effectsNames += modifier.name;
  }
});

if (healing > 0 && token.data?.curhp < token.data?.hitpoints) {
  const healingMacro = `\`\`\`Apply_Healing
const healing = ${healing};

let targets = api.getSelectedOrDroppedToken();

// If record is not null, check if we're the GM or owner and use it
if (record) {
  if (isGM || record?.record?.ownerId === userId) {
    targets = [record];
  }
}

// If we're a player and we did not drop on a record, get our owned tokens
if (!isGM && targets.length === 0) {
    targets = api.getSelectedOwnedTokens().map(target => target.token);
}

targets.forEach(target => {
  // Apply healing
  if (target && target.data) {
    var curhp = target.data?.curhp || 0;
    curhp += healing;
    if (curhp > target.data?.hitpoints) { curhp = target.data?.hitpoints; }
    const oldHp = (target.data?.curhp || 0);
    api.setValueOnToken(target, "data.curhp", curhp);
    const unIdentified = target.identified === false;
    let targetName = !unIdentified ? target.name || target.record.name : target.unidentifiedName || target.record.unidentifiedName;
    targetName = targetName.replace(/'/g, ''); // Just remove the single quotes

    const macro = \`\\\`\\\`\\\`Undo\\n if (isGM) { api.setValueOnTokenById('\$\{target._id\}', '\$\{target.recordType\}', 'data.curhp', '\$\{oldHp\}'); api.editMessage(null, '~\$\{targetName\} healed for \$\{healing\} HP.~'); } else { api.showNotification('Only the GM can undo healing.', 'yellow', 'Notice'); } \\n\\\`\\\`\\\`\`;

    api.sendMessage(\`\$\{targetName\} healed for \$\{healing\} HP.\\n\$\{macro\}\`, undefined, undefined, undefined, target);

    // If healing > 0, float text
    if (healing > 0) {
      api.floatText(target, \`+\${healing}\`, "#1bc91b");
    }
  }
});
\`\`\``;

  const message = `Regenerates ${healing} HP, unless deactivated.\n\n${healingMacro}`;
  api.sendMessage(message, undefined, [], [], token);
}

combatTracker.onRollInitiative:
const token = data?.token;

const roll = "1d20";

// Get modifiers for initiative, which is a dexterity check
const modifiers = [];

// Add dexterity modifier for PCs
if (token.recordType === "characters") {
  const dexMod = parseInt(token?.data?.dexterityMod || "0", 10);
  modifiers.push({
    name: "Dexterity",
    value: dexMod,
    active: true,
  });
} else {
  // Use NPC's initiative modifier
  const initiativeMod = parseInt(token?.data?.initiativeMod || "0", 10);
  modifiers.push({
    name: "Initiative",
    value: initiativeMod,
    active: true,
  });
}

// Check effects for all initiative bonuses and penalties
const initiativeModifiers = getEffectsAndModifiersForToken(token, [
  "initiativeBonus",
  "initiativePenalty",
]);
initiativeModifiers.forEach((modifier) => {
  modifiers.push(modifier);
});

const dextertyCheckModifiers = getEffectsAndModifiersForToken(
  token,
  ["abilityBonus", "abilityPenalty"],
  "dexterity"
);
dextertyCheckModifiers.forEach((modifier) => {
  modifiers.push(modifier);
});

const tokenName = token.name || token.record?.name;

api.promptRollForToken(
  token,
  `Initiative for ${tokenName}`,
  roll,
  modifiers,
  {
    rollName: "Initiative",
    tooltip: "Initiative Roll",
    dc: 0,
  },
  "initiative"
);

combatTracker.onRollInitiativeGroup:
const token =
  data?.tokens && data?.tokens.length > 0 ? data?.tokens[0] : undefined;

if (token) {
  const roll = "1d20";

  // Get modifiers for initiative, which is a dexterity check
  const modifiers = [];

